mapper.select:
SELECT COUNT(*) FROM games g
WHERE (
    (g.black_user_id = #{userId} AND g.outcome = 'BLACK_WIN')
    OR (g.white_user_id = #{userId} AND g.outcome = 'WHITE_WIN')
)
  AND g.created_at >= #{startInclusive}
  AND g.created_at < #{endExclusive}

  AND g.id < #{beforeIdExclusive}

choose.otherwise:
SELECT * FROM ( SELECT g.id, g.room_id AS roomId, g.match_round AS matchRound, g.total_steps AS totalSteps, g.outcome, g.created_at AS createdAt, g.black_user_id AS blackUserId, g.white_user_id AS whiteUserId, ou.nickname AS opponentNickname, ou.is_bot AS opponentBot, ou.avatar_url AS opponentAvatarUrl, ou.gender AS opponentGender FROM games g INNER JOIN users ou ON ou.id = g.white_user_id WHERE g.black_user_id = #{userId}
AND g.outcome = 'BLACK_WIN'
AND g.outcome = 'WHITE_WIN'
UNION ALL SELECT g.id, g.room_id AS roomId, g.match_round AS matchRound, g.total_steps AS totalSteps, g.outcome, g.created_at AS createdAt, g.black_user_id AS blackUserId, g.white_user_id AS whiteUserId, ou.nickname AS opponentNickname, ou.is_bot AS opponentBot, ou.avatar_url AS opponentAvatarUrl, ou.gender AS opponentGender FROM games g INNER JOIN users ou ON ou.id = g.black_user_id WHERE g.white_user_id = #{userId}
AND g.outcome = 'WHITE_WIN'
AND g.outcome = 'BLACK_WIN'
) h ORDER BY h.createdAt DESC LIMIT #{limit} OFFSET #{offset}
